129	export const runScenario = (scenario: any): unknown => {
130	  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
131	  let quoteIndex = 0;
132	  const policies: Record<number, Policy> = {};
133	  const results = scenario.steps.map((step: any, stepIndex: number) => {
134	    if (step.op === "claim") {
135	      return handleClaim(step, policies);
136	    }
137	    validateItemTypes(step.items);
138	    const premium = quotePremium(step.items, yearsWithMHPCO, quoteIndex);
139	    const insuranceSum = insuranceSumFor(step.items);
140	    policies[stepIndex] = {
141	      items: step.items,
142	      insuranceSum,
143	      remainingCap: insuranceSum * CAP_MULTIPLIER,
144	    };
145	    quoteIndex++;
146	    return { premium };
147	  });
148	  return { results };
149	};
